use strict;
use warnings;
use PDF::API2;
use PDF::TextExtractor;

# Function to extract text from a PDF
sub extract_text_from_pdf {
    my ($pdf_file) = @_;
    my $text = '';
    my $extractor = PDF::TextExtractor->new($pdf_file);

    # Extract text from all pages
    while (my ($page_num, $page_text) = $extractor->words) {
        $text .= $page_text;
    }

    return $text;
}

# Main script
